# backend/routes/chat.py
import json
from fastapi import APIRouter, Depends, HTTPException
from fastapi.responses import StreamingResponse
from anthropic import AsyncAnthropic, APIStatusError

from .auth import get_current_user
from .schemas import ChatRequest

router = APIRouter()
client = AsyncAnthropic()

def _sse(data: dict) -> str:
    return f"data: {json.dumps(data)}\n\n"

def _sse_event(event: str, data: dict) -> str:
    return f"event: {event}\ndata: {json.dumps(data)}\n\n"

async def _stream_response(req: ChatRequest, user_id: str):
    """Async generator: yields SSE-formatted strings."""
    try:
        async with client.messages.stream(
            model=req.model,
            max_tokens=req.max_tokens,
            system=req.system,
            messages=req.messages,
        ) as stream:
            async for text_delta in stream.text_stream:
                yield _sse({"delta": text_delta})

            # Emit usage metadata after completion
            usage = (await stream.get_final_message()).usage
            yield _sse({
                "done": True,
                "usage": {
                    "input_tokens": usage.input_tokens,
                    "output_tokens": usage.output_tokens,
                },
            })

    except APIStatusError as exc:
        if exc.status_code == 429:
            yield _sse_event("error", {"code": "rate_limit", "message": "Rate limit exceeded"})
        elif exc.status_code == 400:
            yield _sse_event("error", {"code": "invalid_request", "message": str(exc.message)})
        else:
            yield _sse_event("error", {"code": "api_error", "message": "Upstream error"})
    except Exception:
        yield _sse_event("error", {"code": "server_error", "message": "Internal error"})

@router.post("/v1/chat/completions")
async def chat_completions(
    req: ChatRequest,
    user=Depends(get_current_user),
):
    return StreamingResponse(
        _stream_response(req, user.id),
        media_type="text/event-stream",
        headers={
            "Cache-Control": "no-cache",
            "X-Accel-Buffering": "no",   # disable nginx buffering
        },
    )

# nginx.conf — upstream for the FastAPI container
location /v1/chat/ {
    proxy_pass         http://api:8000;
    proxy_http_version 1.1;
    proxy_buffering    off;          # disable response buffering
    proxy_cache        off;
    proxy_set_header   Connection '';
    chunked_transfer_encoding on;
    proxy_read_timeout 300s;         # allow long model responses
}

// hooks/useChatStream.ts
import { useCallback, useRef, useState } from "react";

type Message = { role: "user" | "assistant"; content: string };

export function useChatStream(apiUrl: string, token: string) {
  const [messages, setMessages] = useState<Message[]>([]);
  const [streaming, setStreaming] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const abortRef = useRef<AbortController | null>(null);

  const send = useCallback(async (userText: string) => {
    abortRef.current?.abort();
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    const userMsg: Message = { role: "user", content: userText };
    setMessages(prev => [...prev, userMsg]);
    setStreaming(true);
    setError(null);

    let accumulated = "";

    try {
      const resp = await fetch(`${apiUrl}/v1/chat/completions`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({ messages: [...messages, userMsg] }),
        signal: ctrl.signal,
      });

      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);

      const reader = resp.body!.getReader();
      const decoder = new TextDecoder();
      let buffer = "";

      while (true) {
        const { done, value } = await reader.read();
        if (done) break;

        buffer += decoder.decode(value, { stream: true });
        const parts = buffer.split("\n\n");
        buffer = parts.pop() ?? "";   // keep incomplete tail

        for (const part of parts) {
          const line = part.trim();
          if (!line.startsWith("data:")) continue;
          const raw = line.slice(5).trim();
          if (raw === "[DONE]") continue;

          const evt = JSON.parse(raw);
          if (evt.delta) {
            accumulated += evt.delta;
            setMessages(prev => {
              const next = [...prev];
              const last = next[next.length - 1];
              if (last?.role === "assistant") {
                next[next.length - 1] = { ...last, content: accumulated };
              } else {
                next.push({ role: "assistant", content: accumulated });
              }
              return next;
            });
          }
          if (evt.done) {
            // usage data available in evt.usage
          }
        }
      }
    } catch (err) {
      if ((err as Error).name !== "AbortError") {
        setError((err as Error).message);
      }
    } finally {
      setStreaming(false);
    }
  }, [apiUrl, token, messages]);

  const stop = useCallback(() => {
    abortRef.current?.abort();
    setStreaming(false);
  }, []);

  return { messages, streaming, error, send, stop };
}

// Extend the parser loop to handle named events:
let eventType = "message";
for (const rawLine of part.split("\n")) {
  if (rawLine.startsWith("event:")) {
    eventType = rawLine.slice(6).trim();
  } else if (rawLine.startsWith("data:")) {
    const raw = rawLine.slice(5).trim();
    const evt = JSON.parse(raw);
    if (eventType === "error") {
      setError(evt.message ?? "Stream error");
    } else if (evt.delta) {
      accumulated += evt.delta;
      // ... update messages state ...
    }
    eventType = "message"; // reset
  }
}

// Client: store last-event-id and pass it on retry
let lastEventId = "";

// In the SSE parser loop, check for id: lines:
if (rawLine.startsWith("id:")) {
  lastEventId = rawLine.slice(3).trim();
}

// When retrying after disconnect:
const resp = await fetch(url, {
  headers: {
    Authorization: `Bearer ${token}`,
    ...(lastEventId ? { "Last-Event-ID": lastEventId } : {}),
  },
  body: JSON.stringify({ messages, resume_from: lastEventId }),
  ...
});
